    "hybridOption": "Hybrid",
    "timeAvailableLabel": "Time available",
    "selectTime": "Select time",
    "time5to10": "5-10 minutes",
    "time15to20": "15-20 minutes",
    "time30": "30 minutes",
    "time45to60": "45-60 minutes",
    "additionalContextLabel": "Additional context (optional)",
    "additionalContextPlaceholder": "Add any specific details about your team, meeting goals, or constraints...",
    "burnedOutTeamButton": "Burned out team",
    "newMembersButton": "New members",
    "remoteTimezoneButton": "Remote/timezone challenges",
    "burnedOutTeamContext": "Team is feeling burned out after a failed project",
    "newMembersContext": "New team members joining, need to build trust quickly",
    "remoteTimezoneContext": "Remote team across multiple time zones, need inclusive activities",
    "fillAllFieldsError": "Please fill in all fields",
    "generateActivitiesError": "Failed to generate activities. Please try again.",
    "generatingActivitiesButton": "Generating activities...",
    "generateActivitiesButton": "Generate activities",
    "yourActivitiesTitle": "Your activities",
    "regenerateButton": "Regenerate",
    "facilitationTipsTitle": "Facilitation tips:"
  },
  /* LOCALE_PLACEHOLDER_START */
  "es-ES": {
    "pageTitle": "Ideas de actividades para equipos",
    "pageSubtitle": "Obtén ideas de actividades personalizadas para tu equipo - solo describe tu reunión.",
    "meetingTypeLabel": "Tipo de reunión",
    "selectMeetingType": "Seleccionar tipo de reunión",
    "teamBuildingOption": "Construcción de equipo",
    "brainstormingOption": "Lluvia de ideas",
    "retrospectiveOption": "Retrospectiva",
    "kickoffMeetingOption": "Reunión de inicio",
    "problemSolvingOption": "Resolución de problemas",
    "strategySessionOption": "Sesión de estrategia",
    "creativeWorkshopOption": "Taller creativo",
    "allHandsMeetingOption": "Reunión general",
    "teamSizeLabel": "Tamaño del equipo",
    "selectTeamSize": "Seleccionar tamaño del equipo",
    "teamSize2to5": "2-5 personas",
    "teamSize6to10": "6-10 personas",
    "teamSize11to20": "11-20 personas",
    "teamSize20plus": "20+ personas",
    "locationLabel": "Ubicación",
    "selectLocation": "Seleccionar ubicación",
    "inPersonOption": "Presencial",
    "virtualOption": "Virtual",
    "hybridOption": "Híbrido",
    "timeAvailableLabel": "Tiempo disponible",
    "selectTime": "Seleccionar tiempo",
    "time5to10": "5-10 minutos",
    "time15to20": "15-20 minutos",
    "time30": "30 minutos",
    "time45to60": "45-60 minutos",
    "additionalContextLabel": "Contexto adicional (opcional)",
    "additionalContextPlaceholder": "Añade detalles específicos sobre tu equipo, objetivos de la reunión o limitaciones...",
    "burnedOutTeamButton": "Equipo agotado",
    "newMembersButton": "Nuevos miembros",
    "remoteTimezoneButton": "Desafíos remotos/zona horaria",
    "burnedOutTeamContext": "El equipo se siente agotado después de un proyecto fallido",
    "newMembersContext": "Se unen nuevos miembros al equipo, necesidad de construir confianza rápidamente",
    "remoteTimezoneContext": "Equipo remoto en múltiples zonas horarias, necesita actividades inclusivas",
    "fillAllFieldsError": "Por favor completa todos los campos",
    "generateActivitiesError": "Error al generar actividades. Por favor inténtalo de nuevo.",
    "generatingActivitiesButton": "Generando actividades...",
    "generateActivitiesButton": "Generar actividades",
    "yourActivitiesTitle": "Tus actividades",
    "regenerateButton": "Regenerar",
    "facilitationTipsTitle": "Consejos de facilitación:"
  }
  /* LOCALE_PLACEHOLDER_END */
};

const appLocale = '{{APP_LOCALE}}';
const browserLocale = navigator.languages?.[0] || navigator.language || 'en-US';
const findMatchingLocale = (locale) => {
  if (TRANSLATIONS[locale]) return locale;
  const lang = locale.split('-')[0];
  const match = Object.keys(TRANSLATIONS).find(key => key.startsWith(lang + '-'));
  return match || 'en-US';
};
const locale = (appLocale !== '{{APP_LOCALE}}') ? findMatchingLocale(appLocale) : findMatchingLocale(browserLocale);
const t = (key) => TRANSLATIONS[locale]?.[key] || TRANSLATIONS['en-US'][key] || key;

const TeamActivityGenerator = () => {
  const [meetingType, setMeetingType] = useState('');
  const [teamSize, setTeamSize] = useState('');
  const [location, setLocation] = useState('');
  const [timeAvailable, setTimeAvailable] = useState('');
  const [additionalContext, setAdditionalContext] = useState('');
  const [activities, setActivities] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const meetingTypes = [
    { key: 'teamBuildingOption', value: 'Team building' },
    { key: 'brainstormingOption', value: 'Brainstorming' },
    { key: 'retrospectiveOption', value: 'Retrospective' },
    { key: 'kickoffMeetingOption', value: 'Kickoff meeting' },
    { key: 'problemSolvingOption', value: 'Problem solving' },
    { key: 'strategySessionOption', value: 'Strategy session' },
    { key: 'creativeWorkshopOption', value: 'Creative workshop' },
    { key: 'allHandsMeetingOption', value: 'All hands meeting' }
  ];

  const teamSizes = [
    { key: 'teamSize2to5', value: '2-5 people' },
    { key: 'teamSize6to10', value: '6-10 people' },
    { key: 'teamSize11to20', value: '11-20 people' },
    { key: 'teamSize20plus', value: '20+ people' }
  ];

  const locations = [
    { key: 'inPersonOption', value: 'In-person' },
    { key: 'virtualOption', value: 'Virtual' },
    { key: 'hybridOption', value: 'Hybrid' }
  ];

  const timeOptions = [
    { key: 'time5to10', value: '5-10 minutes' },
    { key: 'time15to20', value: '15-20 minutes' },
    { key: 'time30', value: '30 minutes' },
    { key: 'time45to60', value: '45-60 minutes' }
  ];

  const generateActivities = async () => {
    if (!meetingType || !teamSize || !location || !timeAvailable) {
      setError(t('fillAllFieldsError'));
      return;
    }

    setLoading(true);
    setError('');

    try {
      const prompt = `Generate 3-5 team activities for a ${meetingType} meeting with the following context:
      - Team size: ${teamSize}
      - Location: ${location}
      - Time available: ${timeAvailable}
      ${additionalContext ? `- Additional context: ${additionalContext}` : ''}

      For each activity, provide:
      1. Activity name
      2. Brief description (1-2 sentences)
      3. Time required
      4. Facilitation tips (2-3 bullet points)

      Make the activities engaging, appropriate for the meeting type, and feasible within the constraints.

      Format your response as a JSON array of objects with the following structure:
      [
        {
          "name": "Activity Name",
          "description": "Brief description",
          "timeRequired": "X minutes",
          "facilitationTips": ["Tip 1", "Tip 2", "Tip 3"]
        }
      ]

      Please respond in ${locale} language.

      Respond ONLY with the JSON array, no additional text.`;

      const response = await window.claude.complete(prompt);
      const parsedActivities = JSON.parse(response);
      setActivities(parsedActivities);
    } catch (error) {
      console.error('Error generating activities:', error);
      setError(t('generateActivitiesError'));
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen p-6 pt-12" style={{ backgroundColor: '#F4DB84' }}>
      <div className="max-w-3xl mx-auto">
        <div className="text-center mb-8">
          <h1 className="text-4xl font-bold mb-3" style={{ color: '#423404' }}>
            {t('pageTitle')}
          </h1>
          <p className="text-lg" style={{ color: '#423404' }}>
            {t('pageSubtitle')}
          </p>
        </div>

        <div className="bg-white rounded-2xl shadow-lg p-6 mb-8">
          <div className="grid grid-cols-2 gap-4">
            {/* Meeting Type */}
            <div className="relative">
              <label className="block text-sm font-medium text-gray-700 mb-2">
                {t('meetingTypeLabel')}
              </label>
              <div className="relative">
                <select
                  value={meetingType}
                  onChange={(e) => setMeetingType(e.target.value)}
                  className="w-full appearance-none bg-gray-50 border border-gray-300 rounded-lg py-2.5 px-3 pr-10 focus:outline-none focus:ring-2 focus:ring-yellow-500 focus:border-transparent"
                >
                  <option value="">{t('selectMeetingType')}</option>
                  {meetingTypes.map((type) => (
                    <option key={type.value} value={type.value}>
                      {t(type.key)}
                    </option>
                  ))}
                </select>
                <ChevronDown className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-500 pointer-events-none" size={18} />
              </div>
            </div>

            {/* Team Size */}
            <div className="relative">
              <label className="block text-sm font-medium text-gray-700 mb-2">
                <Users className="inline mr-2" size={16} />
                {t('teamSizeLabel')}
              </label>
              <div className="relative">
                <select
                  value={teamSize}
                  onChange={(e) => setTeamSize(e.target.value)}
                  className="w-full appearance-none bg-gray-50 border border-gray-300 rounded-lg py-2.5 px-3 pr-10 focus:outline-none focus:ring-2 focus:ring-yellow-500 focus:border-transparent"
                >
                  <option value="">{t('selectTeamSize')}</option>
                  {teamSizes.map((size) => (
                    <option key={size.value} value={size.value}>
                      {t(size.key)}
                    </option>
                  ))}
                </select>
                <ChevronDown className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-500 pointer-events-none" size={18} />
              </div>
            </div>

            {/* Location */}
            <div className="relative">
              <label className="block text-sm font-medium text-gray-700 mb-2">
                <Globe className="inline mr-2" size={16} />
                {t('locationLabel')}
              </label>
              <div className="relative">
                <select
                  value={location}
                  onChange={(e) => setLocation(e.target.value)}
                  className="w-full appearance-none bg-gray-50 border border-gray-300 rounded-lg py-2.5 px-3 pr-10 focus:outline-none focus:ring-2 focus:ring-yellow-500 focus:border-transparent"
                >
                  <option value="">{t('selectLocation')}</option>
                  {locations.map((loc) => (
                    <option key={loc.value} value={loc.value}>
                      {t(loc.key)}
                    </option>
                  ))}
                </select>
                <ChevronDown className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-500 pointer-events-none" size={18} />
              </div>
            </div>

            {/* Time Available */}
            <div className="relative">
              <label className="block text-sm font-medium text-gray-700 mb-2">
                <Clock className="inline mr-2" size={16} />
                {t('timeAvailableLabel')}
              </label>
              <div className="relative">
                <select
                  value={timeAvailable}
                  onChange={(e) => setTimeAvailable(e.target.value)}
                  className="w-full appearance-none bg-gray-50 border border-gray-300 rounded-lg py-2.5 px-3 pr-10 focus:outline-none focus:ring-2 focus:ring-yellow-500 focus:border-transparent"
                >
                  <option value="">{t('selectTime')}</option>
                  {timeOptions.map((time) => (
                    <option key={time.value} value={time.value}>
                      {t(time.key)}
                    </option>
                  ))}
                </select>
                <ChevronDown className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-500 pointer-events-none" size={18} />
              </div>
            </div>
          </div>

          {/* Additional Context */}
          <div className="mt-4">
            <label className="block text-sm font-medium text-gray-700 mb-2">
              {t('additionalContextLabel')}
            </label>
            <textarea
              value={additionalContext}
              onChange={(e) => setAdditionalContext(e.target.value)}
              placeholder={t('additionalContextPlaceholder')}
              className="w-full bg-gray-50 border border-gray-300 rounded-lg py-2.5 px-3 focus:outline-none focus:ring-2 focus:ring-yellow-500 focus:border-transparent resize-none"
              rows={3}
            />
            <div className="flex gap-2 mt-2">
              <button
                onClick={() => setAdditionalContext(t('burnedOutTeamContext'))}
                className="px-3 py-1.5 text-sm bg-gray-100 hover:bg-gray-200 text-gray-700 rounded-lg transition-colors"
              >
                {t('burnedOutTeamButton')}
              </button>
              <button
                onClick={() => setAdditionalContext(t('newMembersContext'))}
                className="px-3 py-1.5 text-sm bg-gray-100 hover:bg-gray-200 text-gray-700 rounded-lg transition-colors"
              >
                {t('newMembersButton')}
              </button>
              <button
                onClick={() => setAdditionalContext(t('remoteTimezoneContext'))}
                className="px-3 py-1.5 text-sm bg-gray-100 hover:bg-gray-200 text-gray-700 rounded-lg transition-colors"
              >
                {t('remoteTimezoneButton')}
              </button>
            </div>
          </div>

          {error && (
            <div className="mt-4 p-3 bg-red-100 border border-red-400 text-red-700 rounded-lg">
              {error}
            </div>
          )}

          <button
            onClick={generateActivities}
            disabled={loading}
            className="mt-6 w-full bg-gray-900 text-white py-3 px-6 rounded-lg font-semibold hover:bg-gray-800 transition-colors duration-200 flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {loading ? (
              <>
                <Loader2 className="animate-spin mr-2" size={20} />
                {t('generatingActivitiesButton')}
              </>
            ) : (
              t('generateActivitiesButton')
            )}
          </button>
        </div>

        {/* Activities Display */}
        {activities.length > 0 && (
          <div className="space-y-4">
            <div className="flex justify-between items-center mb-4">
              <h2 className="text-2xl font-bold text-gray-900">{t('yourActivitiesTitle')}</h2>
              <button
                onClick={generateActivities}
                className="bg-white text-gray-900 py-2 px-4 rounded-lg font-medium hover:bg-gray-100 transition-colors duration-200 flex items-center"
              >
                <RefreshCw className="mr-2" size={16} />
                {t('regenerateButton')}
              </button>
            </div>

            {activities.map((activity, index) => (
              <div
                key={index}
                className="bg-white rounded-xl shadow-md p-6 hover:shadow-lg transition-shadow duration-200"
              >
                <div className="flex justify-between items-start mb-3">
                  <h3 className="text-xl font-semibold text-gray-900">
                    {activity.name}
                  </h3>
                  <span className="bg-yellow-100 text-yellow-800 text-sm font-medium px-3 py-1 rounded-full">
                    <Clock className="inline mr-1" size={14} />
                    {activity.timeRequired}
                  </span>
                </div>

                <p className="text-gray-700 mb-4">
                  {activity.description}
                </p>

                <div className="border-t pt-4">
                  <h4 className="font-medium text-gray-900 mb-2">{t('facilitationTipsTitle')}</h4>
                  <ul className="space-y-2">
                    {activity.facilitationTips.map((tip, tipIndex) => (
                      <li key={tipIndex} className="flex items-start">
                        <span className="bg-yellow-400 rounded-full w-2 h-2 mt-2 mr-3 flex-shrink-0"></span>
                        <span className="text-gray-700">{tip}</span>
                      </li>
                    ))}
                  </ul>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default TeamActivityGenerator;
